// Returns a pointer to the dictionary array for the given instrument.
// Each dictionary is float[49][512].
inline const float (*getDictionary(Instrument inst))[512]
{
    switch (inst)
    {
        case Instrument::Guitar: return guitarDict;
        case Instrument::Keyboard: return keyboardDict;
        case Instrument::Voice: return voiceDict;
        default: return nullptr;
    }
}

